def max_fill(grid, capacity):
    n = len(grid)
    m = len(grid[0])
    dp = [[0]*m for _ in range(n)]
    bucket = [0]*n
    res = 0

    for i in range(n):
        for j in range(m):
            if grid[i][j] == 1:
                dp[i][j] = dp[i-1][j] + 1 if i > 0 else 1
                bucket[i] += dp[i][j]

    for i in range(n-1, -1, -1):
        if bucket[i] > capacity:
            res += bucket[i] // capacity
            bucket[i] %= capacity

    return res

